class Solution:
    def sumNumbers(self, root):
        nums = []
        def walk(node, s):
            if node is None:
                return
            s = s + str(node.val)
            if node.left is None and node.right is None:
                nums.append(int(s))
                return
            walk(node.left, s)
            walk(node.right, s)
        walk(root, '')
        return sum(nums)

